    [Parameter] public RunState Run { get; set; } = null!;
    [Parameter] public MapNode Node { get; set; } = null!;
    [Parameter] public EventCallback<bool> OnCombatEnd { get; set; }
    
    private GameEngine engine = new();
    private AIEngine aiEngine = null!;
    private GameState? state;
    private PlayerState player = null!;
    private PlayerState enemy = null!;
    private int goldReward;
    private List<string> cardRewards = new();
    private List<string> combatLog = new();
    
    protected override void OnInitialized()
    {
        aiEngine = new AIEngine(engine);
        state = engine.InitializeCombat(Run, Node.EnemyId!);
        
        // Process initial draw phase
        if (state.Phase == "DRAW")
        {
            state = engine.ProcessAction(state, new GameAction { Type = "DRAW_CARD", PlayerId = 1 });
        }
        
        UpdatePlayerRefs();
        
        var enemyDef = Database.Instance.GetEnemy(Node.EnemyId!);
        AddLog($"⚔️ Battle begins against {enemyDef?.Name}!");
        AddLog($"📜 Drew {player.Hand.Count} cards");
    }
    
    private void UpdatePlayerRefs()
    {
        if (state == null) return;
        player = state.Players.First(p => p.PlayerId == 1);
        enemy = state.Players.First(p => p.PlayerId == 2);
    }
    
    private void AddLog(string message)
    {
        combatLog.Add(message);
        if (combatLog.Count > 20) combatLog.RemoveAt(0);
    }
    
    private async Task PlayCard(CardInstance card)
    {
        if (state == null) return;
        
        var cardDef = Database.Instance.GetCard(card.CardId);
        var oldEnemyHP = enemy.HP;
        
        state = engine.ProcessAction(state, new GameAction
        {
            Type = "PLAY_CARD",
            PlayerId = 1,
            CardInstanceId = card.InstanceId,
            TargetPlayerId = 2
        });
        
        UpdatePlayerRefs();
        
        var damage = oldEnemyHP - enemy.HP;
        if (damage > 0)
            AddLog($"🗡️ {cardDef?.Name} dealt {damage} damage!");
        else
            AddLog($"✨ Played {cardDef?.Name}");
        
        StateHasChanged();
        await CheckGameOver();
    }
    
    private async Task UseItem(string itemId)
    {
        if (state == null) return;
        
        var item = Database.Instance.GetItem(itemId);
        
        state = engine.ProcessAction(state, new GameAction
        {
            Type = "USE_ITEM",
            PlayerId = 1,
            ItemId = itemId
        });
        
        UpdatePlayerRefs();
        AddLog($"💊 Used {item?.Name}");
        
        StateHasChanged();
        await CheckGameOver();
    }
    
    private async Task EndTurn()
    {
        if (state == null) return;
        
        AddLog("⏭️ Turn ended");
        state = engine.ProcessAction(state, new GameAction { Type = "END_TURN", PlayerId = 1 });
        UpdatePlayerRefs();
        
        if (!state.IsGameOver)
        {
            await Task.Delay(500);
            StateHasChanged();
            
            var enemyDef = Database.Instance.GetEnemy(Node.EnemyId!);
            AddLog($"👹 {enemy.Name}'s turn...");
            
            state = aiEngine.ExecuteAITurn(state, 2, enemyDef?.AIPattern ?? "AGGRESSIVE", Node.EnemyId!);
            UpdatePlayerRefs();
            
            if (aiEngine.Log.Entries.Count > 0)
            {
                foreach (var entry in aiEngine.Log.Entries)
                    AddLog($"🎯 {entry}");
            }
            
            // Process draw phase for player's next turn
            if (state.Phase == "DRAW")
            {
                state = engine.ProcessAction(state, new GameAction { Type = "DRAW_CARD", PlayerId = 1 });
                UpdatePlayerRefs();
                AddLog($"📜 Drew {player.Hand.Count} cards");
            }
            
            await CheckGameOver();
        }
    }
    
    private async Task CheckGameOver()
    {
        if (state?.IsGameOver == true && state.WinnerPlayerId == 1)
        {
            var enemyDef = Database.Instance.GetEnemy(Node.EnemyId!);
            goldReward = enemyDef?.GoldReward ?? 0;
            new RunManager().AddGold(Run, goldReward);
            
            var rng = new Random(Run.Seed + Run.TotalCombats);
            var manager = new RunManager();
            var rarity = manager.GetRandomRarity(rng);
            cardRewards = manager.GetAvailableCards(rarity, rng);
            Run.TotalCombats++;
            
            AddLog($"🏆 Victory! Earned {goldReward} gold");
            AddLog($"✨ {rarity} card rewards available!");
        }
        else if (state?.IsGameOver == true)
        {
            AddLog("💀 You have been defeated...");
        }
        
        StateHasChanged();
    }
    
    private void SelectCardReward(string cardId)
    {
        new RunManager().AddCardToRun(Run, cardId);
        Run.HP = player.HP;
        OnCombatEnd.InvokeAsync(true);
    }
    
    private void SkipReward()
    {
        Run.HP = player.HP;
        OnCombatEnd.InvokeAsync(true);
    }
    
    private string GetCardEffects(CardDefinition? card, bool upgraded = false)
    {
        if (card == null) return "";
        var effects = upgraded && card.UpgradedEffects.Count > 0 ? card.UpgradedEffects : card.Effects;
        return string.Join(" • ", effects.Select(e => $"{GetEffectIcon(e.Type)} {e.Value}"));
    }
    
    private string GetEffectIcon(string type) => type switch
    {
        "DAMAGE" => "⚔️",
        "HEAL" => "💚",
        "SHIELD" => "🛡️",
        "DRAW" => "📜",
        "POISON" => "☠️",
        "STRENGTH" => "💪",
        "WEAK" => "🔻",
        _ => "✨"
    };
    
    private string GetStatusIcon(string type) => type switch
    {
        "POISON" => "☠️",
        "BURN" => "🔥",
        "REGENERATION" => "💚",
        "STRENGTH" => "💪",
        "WEAK" => "🔻",
        "SHIELD" => "🛡️",
        "STUN" => "😵",
        "SILENT" => "🤐",
        "FEAR" => "😱",
        "ENERGY_SURGE" => "⚡",
        _ => "✨"
    };
    
    private string GetStatusDescription(StatusEffect eff) => eff.Type switch
    {
        "POISON" => $"Takes {eff.Value} damage per turn for {eff.Duration} turns",
        "BURN" => $"Takes {eff.Value} damage per turn for {eff.Duration} turns",
        "REGENERATION" => $"Heals {eff.Value} HP per turn for {eff.Duration} turns",
        "STRENGTH" => $"+{eff.Value} damage for {eff.Duration} turns",
        "WEAK" => $"-{eff.Value} damage for {eff.Duration} turns",
        "SHIELD" => $"{eff.Value} damage absorption",
        "STUN" => $"Cannot play cards for {eff.Duration} turns",
        "SILENT" => $"Cannot play magic cards for {eff.Duration} turns",
        "FEAR" => $"Discards 1 card after playing for {eff.Duration} turns",
        "ENERGY_SURGE" => $"Reduces card cost by {eff.Value} this turn",
        _ => $"{eff.Type}: {eff.Value}"
    };

